    14→ */
    15→
    16→/*
    17→ * int lutil_passwd(
    18→ *	const struct berval *passwd,
    19→ *	const struct berval *cred,
    20→ *	const char **schemes )
    21→ *
    22→ * Returns true if user supplied credentials (cred) matches
    23→ * the stored password (passwd). 
    24→ *
    25→ * Due to the use of the crypt(3) function 
    26→ * this routine is NOT thread-safe.
    27→ */
    28→
    29→#include "portable.h"
    30→
    31→#include <stdio.h>
    32→#include <ac/stdlib.h>
    33→#include <ac/string.h>
    34→#include <ac/unistd.h>
    35→#include <ac/param.h>
    36→
    37→#ifdef SLAPD_CRYPT
    38→# include <ac/crypt.h>
    39→
    40→# if defined( HAVE_GETPWNAM ) && defined( HAVE_STRUCT_PASSWD_PW_PASSWD )
    41→#  ifdef HAVE_SHADOW_H
    42→#	include <shadow.h>
    43→#  endif
    44→#  ifdef HAVE_PWD_H
    45→#	include <pwd.h>
    46→#  endif
    47→#  ifdef HAVE_AIX_SECURITY
    48→#	include <userpw.h>
    49→#  endif
    50→# endif
    51→#endif
    52→
    53→#include <lber.h>
    54→
    55→#include "ldap_pvt.h"
    56→#include "lber_pvt.h"
    57→
    58→#include "lutil_md5.h"
    59→#include "lutil_sha1.h"
    60→#include "lutil.h"
    61→
    62→static const unsigned char crypt64[] =
    63→	"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz1234567890./";
    64→
    65→#ifdef SLAPD_CRYPT
    66→static char *salt_format = NULL;
    67→static lutil_cryptfunc lutil_crypt;
    68→lutil_cryptfunc *lutil_cryptptr = lutil_crypt;
    69→#endif
    70→
    71→/* KLUDGE:
    72→ *  chk_fn is NULL iff name is {CLEARTEXT}
    73→ *	otherwise, things will break
    74→ */
    75→struct pw_scheme {
    76→	struct berval name;
    77→	LUTIL_PASSWD_CHK_FUNC *chk_fn;
    78→	LUTIL_PASSWD_HASH_FUNC *hash_fn;
    79→};
    80→
    81→struct pw_slist {
    82→	struct pw_slist *next;
    83→	struct pw_scheme s;
    84→};
    85→
    86→/* password check routines */
    87→
    88→#define	SALT_SIZE	4
    89→
    90→static LUTIL_PASSWD_CHK_FUNC chk_md5;
    91→static LUTIL_PASSWD_CHK_FUNC chk_smd5;
    92→static LUTIL_PASSWD_HASH_FUNC hash_smd5;
    93→static LUTIL_PASSWD_HASH_FUNC hash_md5;
    94→
    95→
    96→#ifdef LUTIL_SHA1_BYTES
    97→static LUTIL_PASSWD_CHK_FUNC chk_ssha1;
    98→static LUTIL_PASSWD_CHK_FUNC chk_sha1;
    99→static LUTIL_PASSWD_HASH_FUNC hash_sha1;
   100→static LUTIL_PASSWD_HASH_FUNC hash_ssha1;
   101→#endif
   102→
   103→
   104→#ifdef SLAPD_CRYPT
   105→static LUTIL_PASSWD_CHK_FUNC chk_crypt;
   106→static LUTIL_PASSWD_HASH_FUNC hash_crypt;
   107→
   108→#if defined( HAVE_GETPWNAM ) && defined( HAVE_STRUCT_PASSWD_PW_PASSWD )
   109→static LUTIL_PASSWD_CHK_FUNC chk_unix;
   110→#endif
   111→#endif
   112→
   113→/* password hash routines */
   114→
   115→#ifdef SLAPD_CLEARTEXT
   116→static LUTIL_PASSWD_HASH_FUNC hash_clear;
   117→#endif
   118→
   119→static struct pw_slist *pw_schemes;
   120→static int pw_inited;
   121→
   122→static const struct pw_scheme pw_schemes_default[] =
   123→{
   124→#ifdef LUTIL_SHA1_BYTES
   125→	{ BER_BVC("{SSHA}"),		chk_ssha1, hash_ssha1 },
   126→	{ BER_BVC("{SHA}"),			chk_sha1, hash_sha1 },
   127→#endif
   128→
   129→	{ BER_BVC("{SMD5}"),		chk_smd5, hash_smd5 },
   130→	{ BER_BVC("{MD5}"),			chk_md5, hash_md5 },
   131→
   132→#ifdef SLAPD_CRYPT
   133→	{ BER_BVC("{CRYPT}"),		chk_crypt, hash_crypt },
   134→# if defined( HAVE_GETPWNAM ) && defined( HAVE_STRUCT_PASSWD_PW_PASSWD )
   135→	{ BER_BVC("{UNIX}"),		chk_unix, NULL },
   136→# endif
   137→#endif
   138→
   139→#ifdef SLAPD_CLEARTEXT
   140→	/* pseudo scheme */
   141→	{ BER_BVC("{CLEARTEXT}"),	NULL, hash_clear },
   142→#endif
   143→
   144→	{ BER_BVNULL, NULL, NULL }
   145→};
   146→
   147→int lutil_passwd_add(
   148→	struct berval *scheme,
   149→	LUTIL_PASSWD_CHK_FUNC *chk,
   150→	LUTIL_PASSWD_HASH_FUNC *hash )
   151→{
   152→	struct pw_slist *ptr;
   153→
   154→	if (!pw_inited) lutil_passwd_init();
   155→
   156→	ptr = ber_memalloc( sizeof( struct pw_slist ));
   157→	if (!ptr) return -1;
   158→	ptr->next = pw_schemes;
   159→	ptr->s.name = *scheme;
   160→	ptr->s.chk_fn = chk;
   161→	ptr->s.hash_fn = hash;
   162→	pw_schemes = ptr;
   163→	return 0;
   164→}
   165→
   166→void lutil_passwd_init()
   167→{
   168→	struct pw_scheme *s;
   169→
   170→	pw_inited = 1;
   171→
   172→	for( s=(struct pw_scheme *)pw_schemes_default; s->name.bv_val; s++) {
   173→		if ( lutil_passwd_add( &s->name, s->chk_fn, s->hash_fn ) ) break;
   174→	}
   175→}
   176→
   177→void lutil_passwd_destroy()
   178→{
   179→	struct pw_slist *ptr, *next;
   180→
   181→	for( ptr=pw_schemes; ptr; ptr=next ) {
   182→		next = ptr->next;
   183→		ber_memfree( ptr );
   184→	}
   185→}
   186→
   187→static const struct pw_scheme *get_scheme(
   188→	const char* scheme )
   189→{
   190→	struct pw_slist *pws;
   191→	struct berval bv;
   192→
   193→	if (!pw_inited) lutil_passwd_init();
   194→
   195→	bv.bv_val = strchr( scheme, '}' );
   196→	if ( !bv.bv_val )
   197→		return NULL;
   198→
   199→	bv.bv_len = bv.bv_val - scheme + 1;
   200→	bv.bv_val = (char *) scheme;
   201→
   202→	for( pws=pw_schemes; pws; pws=pws->next ) {
   203→		if ( ber_bvstrcasecmp(&bv, &pws->s.name ) == 0 ) {
   204→			return &(pws->s);
   205→		}
   206→	}
   207→
   208→	return NULL;
   209→}
   210→
   211→int lutil_passwd_scheme(
   212→	const char* scheme )
   213→{
   214→	if( scheme == NULL ) {
   215→		return 0;
   216→	}
   217→
   218→	return get_scheme(scheme) != NULL;
   219→}
   220→
   221→
   222→static int is_allowed_scheme( 
   223→	const char* scheme,
   224→	const char** schemes )
   225→{
   226→	int i;
   227→
   228→	if( schemes == NULL ) return 1;
   229→
   230→	for( i=0; schemes[i] != NULL; i++ ) {
   231→		if( strcasecmp( scheme, schemes[i] ) == 0 ) {
   232→			return 1;
   233→		}
   234→	}
   235→	return 0;
   236→}
   237→
   238→static struct berval *passwd_scheme(
   239→	const struct pw_scheme *scheme,
   240→	const struct berval * passwd,
   241→	struct berval *bv,
   242→	const char** allowed )
   243→{
   244→	if( !is_allowed_scheme( scheme->name.bv_val, allowed ) ) {
   245→		return NULL;
   246→	}
   247→
   248→	if( passwd->bv_len >= scheme->name.bv_len ) {
   249→		if( strncasecmp( passwd->bv_val, scheme->name.bv_val, scheme->name.bv_len ) == 0 ) {
   250→			bv->bv_val = &passwd->bv_val[scheme->name.bv_len];
   251→			bv->bv_len = passwd->bv_len - scheme->name.bv_len;
   252→
   253→			return bv;
   254→		}
   255→	}
   256→
   257→	return NULL;
   258→}
   259→
   260→/*
   261→ * Return 0 if creds are good.
   262→ */
   263→int
   264→lutil_passwd(
   265→	const struct berval *passwd,	/* stored passwd */
   266→	const struct berval *cred,		/* user cred */
   267→	const char **schemes,
   268→	const char **text )
   269→{
   270→	struct pw_slist *pws;
   271→
   272→	if ( text ) *text = NULL;
   273→
   274→	if (cred == NULL || cred->bv_len == 0 ||
   275→		passwd == NULL || passwd->bv_len == 0 )
   276→	{
   277→		return -1;
   278→	}
   279→
   280→	if (!pw_inited) lutil_passwd_init();
   281→
   282→	for( pws=pw_schemes; pws; pws=pws->next ) {
   283→		if( pws->s.chk_fn ) {
   284→			struct berval x;
   285→			struct berval *p = passwd_scheme( &(pws->s),
   286→				passwd, &x, schemes );
   287→
   288→			if( p != NULL ) {
   289→				return (pws->s.chk_fn)( &(pws->s.name), p, cred, text );
   290→			}
   291→		}
   292→	}
   293→
   294→#ifdef SLAPD_CLEARTEXT
   295→	/* Do we think there is a scheme specifier here that we
   296→	 * didn't recognize? Assume a scheme name is at least 1 character.
   297→	 */
   298→	if (( passwd->bv_val[0] == '{' ) &&
   299→		( ber_bvchr( passwd, '}' ) > passwd->bv_val+1 ))
   300→	{
   301→		return 1;
   302→	}
   303→	if( is_allowed_scheme("{CLEARTEXT}", schemes ) ) {
   304→		return ( passwd->bv_len == cred->bv_len ) ?
   305→			memcmp( passwd->bv_val, cred->bv_val, passwd->bv_len )
   306→			: 1;
   307→	}
   308→#endif
   309→	return 1;
   310→}
   311→
   312→int lutil_passwd_generate( struct berval *pw, ber_len_t len )
   313→{
   314→
   315→	if( len < 1 ) return -1;
   316→
   317→	pw->bv_len = len;
   318→	pw->bv_val = ber_memalloc( len + 1 );
   319→
   320→	if( pw->bv_val == NULL ) {
   321→		return -1;
   322→	}
   323→
   324→	if( lutil_entropy( (unsigned char *) pw->bv_val, pw->bv_len) < 0 ) {
   325→		return -1; 
   326→	}
   327→
   328→	for( len = 0; len < pw->bv_len; len++ ) {
   329→		pw->bv_val[len] = crypt64[
   330→			pw->bv_val[len] % (sizeof(crypt64)-1) ];
   331→	}
   332→
   333→	pw->bv_val[len] = '\0';
   334→	
   335→	return 0;
   336→}
   337→
   338→int lutil_passwd_hash(
   339→	const struct berval * passwd,
   340→	const char * method,
   341→	struct berval *hash,
   342→	const char **text )
   343→{
   344→	const struct pw_scheme *sc = get_scheme( method );
   345→
   346→	hash->bv_val = NULL;
   347→	hash->bv_len = 0;
   348→
   349→	if( sc == NULL ) {
   350→		if( text ) *text = "scheme not recognized";
   351→		return -1;
   352→	}
   353→
   354→	if( ! sc->hash_fn ) {
   355→		if( text ) *text = "scheme provided no hash function";
   356→		return -1;
   357→	}
   358→
   359→	if( text ) *text = NULL;
   360→
   361→	return (sc->hash_fn)( &sc->name, passwd, hash, text );
   362→}
   363→
   364→/* pw_string is only called when SLAPD_CRYPT is defined */
   365→#if defined(SLAPD_CRYPT)
   366→static int pw_string(
   367→	const struct berval *sc,
   368→	struct berval *passwd )
   369→{
   370→	struct berval pw;
   371→
   372→	pw.bv_len = sc->bv_len + passwd->bv_len;
   373→	pw.bv_val = ber_memalloc( pw.bv_len + 1 );
   374→
   375→	if( pw.bv_val == NULL ) {
   376→		return LUTIL_PASSWD_ERR;
   377→	}
   378→
   379→	AC_MEMCPY( pw.bv_val, sc->bv_val, sc->bv_len );
   380→	AC_MEMCPY( &pw.bv_val[sc->bv_len], passwd->bv_val, passwd->bv_len );
   381→
   382→	pw.bv_val[pw.bv_len] = '\0';
   383→	*passwd = pw;
