   389→int lutil_passwd_string64(
   390→	const struct berval *sc,
   391→	const struct berval *hash,
   392→	struct berval *b64,
   393→	const struct berval *salt )
   394→{
   395→	int rc;
   396→	struct berval string;
   397→	size_t b64len;
   398→
   399→	if( salt ) {
   400→		/* need to base64 combined string */
   401→		string.bv_len = hash->bv_len + salt->bv_len;
   402→		string.bv_val = ber_memalloc( string.bv_len + 1 );
   403→
   404→		if( string.bv_val == NULL ) {
   405→			return LUTIL_PASSWD_ERR;
   406→		}
   407→
   408→		AC_MEMCPY( string.bv_val, hash->bv_val,
   409→			hash->bv_len );
   410→		AC_MEMCPY( &string.bv_val[hash->bv_len], salt->bv_val,
   411→			salt->bv_len );
   412→		string.bv_val[string.bv_len] = '\0';
   413→
   414→	} else {
   415→		string = *hash;
   416→	}
   417→
   418→	b64len = LUTIL_BASE64_ENCODE_LEN( string.bv_len ) + 1;
   419→	b64->bv_len = b64len + sc->bv_len;
   420→	b64->bv_val = ber_memalloc( b64->bv_len + 1 );
   421→
   422→	if( b64->bv_val == NULL ) {
   423→		if( salt ) ber_memfree( string.bv_val );
   424→		return LUTIL_PASSWD_ERR;
   425→	}
   426→
   427→	AC_MEMCPY(b64->bv_val, sc->bv_val, sc->bv_len);
   428→
   429→	rc = lutil_b64_ntop(
   430→		(unsigned char *) string.bv_val, string.bv_len,
   431→		&b64->bv_val[sc->bv_len], b64len );
   432→
   433→	if( salt ) ber_memfree( string.bv_val );
   434→	
   435→	if( rc < 0 ) {
   436→		return LUTIL_PASSWD_ERR;
   437→	}
   438→
   439→	/* recompute length */
   440→	b64->bv_len = sc->bv_len + rc;
   441→	assert( strlen(b64->bv_val) == b64->bv_len );
   442→	return LUTIL_PASSWD_OK;
   443→}
