   451→	const struct berval * cred,
   452→	const char **text )
   453→{
   454→	lutil_SHA1_CTX SHA1context;
   455→	unsigned char SHA1digest[LUTIL_SHA1_BYTES];
   456→	int rc;
   457→	unsigned char *orig_pass = NULL;
   458→	size_t decode_len = LUTIL_BASE64_DECODE_LEN(passwd->bv_len);
   459→
   460→	/* safety check -- must have some salt */
   461→	if (decode_len <= sizeof(SHA1digest)) {
   462→		return LUTIL_PASSWD_ERR;
   463→	}
   464→
   465→	/* decode base64 password */
   466→	orig_pass = (unsigned char *) ber_memalloc(decode_len + 1);
   467→
   468→	if( orig_pass == NULL ) return LUTIL_PASSWD_ERR;
   469→
   470→	rc = lutil_b64_pton(passwd->bv_val, orig_pass, decode_len);
   471→
   472→	/* safety check -- must have some salt */
   473→	if (rc <= (int)(sizeof(SHA1digest))) {
   474→		ber_memfree(orig_pass);
   475→		return LUTIL_PASSWD_ERR;
   476→	}
   477→ 
   478→	/* hash credentials with salt */
   479→	lutil_SHA1Init(&SHA1context);
   480→	lutil_SHA1Update(&SHA1context,
   481→		(const unsigned char *) cred->bv_val, cred->bv_len);
   482→	lutil_SHA1Update(&SHA1context,
   483→		(const unsigned char *) &orig_pass[sizeof(SHA1digest)],
   484→		rc - sizeof(SHA1digest));
   485→	lutil_SHA1Final(SHA1digest, &SHA1context);
   486→ 
   487→	/* compare */
   488→	rc = memcmp((char *)orig_pass, (char *)SHA1digest, sizeof(SHA1digest));
   489→	ber_memfree(orig_pass);
   490→	return rc ? LUTIL_PASSWD_ERR : LUTIL_PASSWD_OK;
   491→}
